grid:









      onchange="onChange$GridVoucherDetail$Item(this);"








      onchange="onChange$GridVoucherDetail$UOM(this);"












      onchange="onChange$GridVoucherDetail$Site(this);"







      onchange="onChange$GridVoucherDetail$Quantity(this);"























